document.addEventListener("DOMContentLoaded",()=>{const t=document.querySelector(".footer");if(!t)return;const e=Array.from(t.children),n=()=>{const t=window.scrollY+window.innerHeight,n=document.documentElement.scrollHeight;t>=n-10?e.forEach((e,t)=>{setTimeout(()=>{e.classList.add("is-visible")},t*150)}):e.forEach(e=>{e.classList.remove("is-visible")})};e.forEach(e=>e.classList.remove("is-visible")),window.addEventListener("scroll",n)})